select
    t1.order_id,
    t1.taskorder_id,
    t1.taskorder_node_id,
    t1.taskorder_status,
    t1.taskorder_result,
    taskorder_handler,
    t1.taskorder_create_time,
    t1.taskorder_deadline_time,
    t1.rn,
    get_json_object(x2.formVariables, '$.name') as taskop_name,
    regexp_replace(
        get_json_object(x2.formVariables, '$.values.label'),
        '^\\\[\"|"\\\]$',
        ''
    ) as taskop_values
from
    (
        select
            order_id,
            taskorder_id,
            taskorder_node_id,
            taskorder_status,
            task_orders,
            taskorder_result,
            taskorder_oplogs,
            get_json_object(
                get_json_object(task_orders, '$.handler'),
                '$.[0].code'
            ) as taskorder_handler,
            get_json_object(task_orders, '$.createTime') as taskorder_create_time,
            get_json_object(task_orders, '$.deadLineTime') as taskorder_deadline_time,
            row_number() over(
                partition by (order_id)
                order by
                    taskorder_create_time desc
            ) as rn --取最新分区的order 
        from
            pdw_order_store_211_order_detail_flow_task_taskorders
        where
            dt = date_format(date_sub(current_date(), 1), 'yyyyMMdd')
            and taskorder_node_id = 'UserTask_08jfekk'
    ) t1 lateral view explode(hivemall.json_split(t1.taskorder_oplogs)) x as taskorder_oplogs lateral view outer explode(
        hivemall.json_split(
            get_json_object(x.taskorder_oplogs, '$.variableGroups')
        )
    ) x1 as variableGroups lateral view outer explode(
        hivemall.json_split(
            get_json_object(x1.variableGroups, '$.formVariables')
        )
    ) x2 as formVariables
where
    get_json_object(x2.formVariables, '$.name') in (
        'rentStartDate',
        'rentEndDate',
        'LastTotal',
        'NewTotal',
        'OldAverage',
        'newRentAverage',
        'neOtherAverage',
        'NewAverage',
        'IncreaseInBusinessTerm1' 
        --续租合同首年整体商务条件vs原合同最后一年涨幅（包含税损） 
        ,'IncreaseInBusinessTerm2')
        --续租合同全租期平均整体商务条件vs原合同最后一年涨幅（包含税损） 
